// EXTRACT TRANSFORM - Clean AI response and combine queries
// ═══════════════════════════════════════════════════════════════════════════

const prepData = $('1️⃣ Prep Query').first().json;
const aiResponse = $input.first().json;

console.log('=== EXTRACT TRANSFORM ===');

let transformedQuery = prepData._original_query;

try {
  // n8n AI node returns text in different places
  let content = '';
  if (aiResponse.text) {
    content = aiResponse.text;
  } else if (aiResponse.response?.text) {
    content = aiResponse.response.text;
  } else if (aiResponse.output) {
    content = aiResponse.output;
  } else if (aiResponse.choices?.[0]?.message?.content) {
    // Fallback for raw API response
    content = aiResponse.choices[0].message.content;
  }

  if (content && content.length > 5) {
    transformedQuery = content
      .replace(/^(keywords?:|search:|query:|result:)/i, '')
      .replace(/[\n\r]+/g, ' ')
      .trim();
    console.log('Transformed OK');
  }
} catch(e) {
  console.log('Transform failed:', e.message);
}

console.log('Original:', prepData._original_query);
console.log('Transformed:', transformedQuery.substring(0, 80));

// Smart combination - original is more important
const originalWords = prepData._original_query.toLowerCase().split(/\s+/);
const transformedWords = transformedQuery.toLowerCase().split(/\s+/);

// Add only new words from transformation
const newWords = transformedWords.filter(w => 
  w.length > 2 && !originalWords.some(ow => ow.includes(w) || w.includes(ow))
);

const combinedQuery = prepData._original_query + ' ' + newWords.slice(0, 10).join(' ');

console.log('Combined:', combinedQuery.substring(0, 100));

return [{ json: {
  ...prepData,
  _query: combinedQuery.trim(),
  _transformed_query: transformedQuery,
  _collection: prepData._collection,
  _qdrant_url: prepData._qdrant_url,
  _qdrant_key: prepData._qdrant_key,
  _step: 'transform_done'
}}];

// ═══════════════════════════════════════════════════════════════════════════
// DDC CWICR - Data Driven Construction Cost Estimator
// https://DataDrivenConstruction.io
// Open source construction cost database with 55,000+ work items
// ═══════════════════════════════════════════════════════════════════════════

// Detailed view with resource prices
const cfg = $('Config').first().json;
const cid = String(cfg.chatId);
const sd = $getWorkflowStaticData('global');
const data = sd.lastResults || {};
const L = data.L || cfg.L || {};
const works = data.works || [];
const sym = L.sym || '€';

function fmtCur(v) { 
  if (!v || v === 0) return sym + ' 0';
  return sym + ' ' + v.toFixed(2); 
}

let msg = `*${L.ready} — ${L.resources}*\n\n`;

works.forEach((w, i) => {
  const qi = { 'high': '●', 'medium': '○', 'low': '◌', 'not_found': '✕' }[w.ql] || '○';

  msg += `*${i+1}. ${w.name}*\n`;
  if (w.rate_code && w.rate_code !== 'NOT_FOUND') {
    msg += `${qi} \`${w.rate_code}\`\n`;
    if (w.rate_name && w.rate_name !== w.name) {
      const rateName = (w.rate_name || '').substring(0, 45);
      msg += `_${rateName}_\n`;
    }
  } else {
    msg += `${qi} _${L.not_found}_\n`;
  }
  msg += `${w.qty} ${w.unit} × ${fmtCur(w.uc)} = *${fmtCur(w.tc)}*\n`;

  // Cost breakdown
  const parts = [];
  if (w.workers_total > 0) parts.push(`${L.workers}: ${fmtCur(w.workers_total)}`);
  if (w.materials_total > 0) parts.push(`${L.materials}: ${fmtCur(w.materials_total)}`);
  if (w.machines_total > 0) parts.push(`${L.machines}: ${fmtCur(w.machines_total)}`);
  if (parts.length > 0) msg += `_${parts.join(' · ')}_\n`;

  // Resources with prices
  const resources = w.resources || [];
  if (resources.length > 0) {
    msg += `\n`;
    const showCount = Math.min(5, resources.length);
    resources.slice(0, showCount).forEach((r, ri) => {
      const isLast = ri === showCount - 1 && resources.length <= 5;
      const prefix = isLast ? '└' : '├';
      const typeTag = r.resource_type === 'labor' ? L.res_labor : r.resource_type === 'machine' ? L.res_machine : L.res_material;
      const resName = (r.resource_name || '').substring(0, 26);
      msg += `${prefix} *${typeTag}*: ${resName}\n`;

      // Show quantity and cost
      const qtyVal = r.scaled_quantity || r.resource_quantity || 0;
      const costVal = r.scaled_cost || r.resource_cost || 0;
      if (costVal > 0) {
        msg += `   ${qtyVal.toFixed(2)} ${r.resource_unit || ''} = ${fmtCur(costVal)}\n`;
      } else {
        msg += `   ${qtyVal.toFixed(2)} ${r.resource_unit || ''}\n`;
      }
    });
    if (resources.length > 5) {
      msg += `└ _...+${resources.length - 5} ${L.resources}_\n`;
    }
  }

  // Scope of work
  const scope = w.scope_of_work || [];
  if (scope.length > 0) {
    msg += `\n📋 *${L.scope_title || 'Scope of Work'}:*\n`;
    scope.forEach((s, si) => {
      const prefix = si === scope.length - 1 ? '└' : '├';
      const sText = (s || '').substring(0, 45);
      msg += `${prefix} ${sText}\n`;
    });
  }
  msg += `\n`;
});

// Summary
msg += `─────────────────────\n`;
const totalParts = [];
if (data.workers_sum > 0) totalParts.push(`${L.workers}: ${fmtCur(data.workers_sum)}`);
if (data.materials_sum > 0) totalParts.push(`${L.materials}: ${fmtCur(data.materials_sum)}`);
if (data.machines_sum > 0) totalParts.push(`${L.machines}: ${fmtCur(data.machines_sum)}`);
if (totalParts.length > 0) msg += totalParts.join('\n') + '\n\n';

msg += `*${L.total}: ${fmtCur(data.total || 0)}*\n`;

return { json: { ...cfg, msg, chatId: cid, bot_token: cfg.bot_token, L } };

