// Create CSV content (Excel-compatible)
let csv = '\uFEFF'; // BOM for UTF-8
csv += `${L.doc_title || 'ESTIMATE'} - ${data.description || 'Estimate'}\n`;
csv += `${L.region || 'Region'} | ${new Date().toLocaleDateString()}\n\n`;

// Headers
csv += `${L.col_pos || 'Pos'};${L.col_code || 'Code'};${L.col_desc || 'Description'};${L.col_unit || 'Unit'};${L.col_qty || 'Qty'};${L.col_price || 'Price'};${L.col_total || 'Total'}\n`;

// Data rows
works.forEach((w, i) => {
  const name = (w.rate_name || w.name || '').replace(/;/g, ',').replace(/\n/g, ' ');
  csv += `${i+1};${w.rate_code || ''};"${name}";${w.rate_unit || w.unit || ''};${(w.qty || 0).toFixed(2)};${(w.uc || 0).toFixed(2)};${(w.tc || 0).toFixed(2)}\n`;

  // Resources
  (w.resources || []).forEach(r => {
    const resName = (r.resource_name || '').replace(/;/g, ',').replace(/\n/g, ' ');
    csv += `;${r.resource_code || ''};"  ${resName}";${r.resource_unit || ''};${(r.scaled_quantity || 0).toFixed(3)};${(r.resource_price || 0).toFixed(2)};${(r.scaled_cost || 0).toFixed(2)}\n`;
  });
});

// Totals
csv += `\n;;;;;${L.total || 'TOTAL'};${(data.total || 0).toFixed(2)}\n`;
csv += `;;;;;${L.workers || 'Labor'};${(data.workers_sum || 0).toFixed(2)}\n`;
csv += `;;;;;${L.materials || 'Materials'};${(data.materials_sum || 0).toFixed(2)}\n`;
csv += `;;;;;${L.machines || 'Equipment'};${(data.machines_sum || 0).toFixed(2)}\n`;

