// ═══════════════════════════════════════════════════════════════════════════
// DDC CWICR - Final message (ultra-compact for Telegram 4096 limit)
// ═══════════════════════════════════════════════════════════════════════════

const d = $('Generate HTML').first().json;
const cid = d.chatId;
const sd = $getWorkflowStaticData('global');
const L = d.L || {};

if (sd.res?.[cid]) delete sd.res[cid];
if (sd.sess?.[cid]) sd.sess[cid].state = 'done';

function fmt(v) { 
  try { return new Intl.NumberFormat(L.loc || 'en', { maximumFractionDigits: 0 }).format(v || 0); } 
  catch(e) { return String(Math.round(v || 0)); } 
}

function fmtCur(v) { 
  const sym = L.sym || '$';
  const num = Math.round(v || 0);
  return sym + ' ' + fmt(num);
}

function esc(s) {
  // Remove ALL markdown special chars to avoid Telegram parse errors
  return String(s || '').replace(/[_*`\[\]()~>#+\-=|{}.!\\]/g, '');
}

function shortName(str, len) {
  str = esc(str);
  if (str.length > len) return str.substring(0, len - 1) + '…';
  return str;
}

const works = d.works || [];
const total = d.total || 0;
const now = new Date();
const dateStr = now.toLocaleDateString(L.loc || 'en', { day: '2-digit', month: '2-digit', year: 'numeric' });

// Build compact message
let lines = [];

// Header
lines.push('*' + esc(L.doc_title || 'COST ESTIMATE') + '*');
lines.push(dateStr + ' · ' + esc(L.region || ''));
lines.push(works.length + ' ' + esc(L.items || 'items'));
lines.push('');

// Works list - super compact
const MAX_ITEMS_SHOWN = 30;
const showWorks = works.slice(0, MAX_ITEMS_SHOWN);

showWorks.forEach((w, i) => {
  const name = shortName(w.rate_name || w.name || '', 20);
  lines.push((i+1) + '. ' + name + ' ' + fmtCur(w.tc));
});

if (works.length > MAX_ITEMS_SHOWN) {
  lines.push('... +' + (works.length - MAX_ITEMS_SHOWN) + ' ' + esc(L.more_resources || 'more'));
}

// Total
lines.push('');
lines.push('*' + esc(L.total || 'TOTAL') + ': ' + fmtCur(total) + '*');
lines.push('');

// Breakdown (one line)
const parts = [];
if (d.workers_sum > 0) parts.push(fmtCur(d.workers_sum));
if (d.materials_sum > 0) parts.push(fmtCur(d.materials_sum));
if (d.machines_sum > 0) parts.push(fmtCur(d.machines_sum));
if (parts.length > 0) lines.push(parts.join(' · '));

// Hours
if (d.labor_hours_sum > 0) {
  const days = Math.ceil(d.labor_hours_sum / 8);
  lines.push(fmt(d.labor_hours_sum) + 'h · ' + days + ' ' + esc(L.days || 'd'));
}

// Build message
let msg = lines.join('\n');

// Hard truncate at 3800 chars to be safe
if (msg.length > 3800) {
  msg = msg.substring(0, 3700);
  msg += '\n\n...\n*' + esc(L.total || 'TOTAL') + ': ' + fmtCur(total) + '*';
}

console.log('Final msg length:', msg.length);

return { json: { ...d, msg } };

