const L = cfg.L || session.L || {};

const idx = session.editingWorkIndex || cfg.editingWorkIndex || 0;
const work = works[idx];

console.log('=== EDIT MENU ===');
console.log('Editing work index:', idx);
console.log('Work:', work?.name);

if (!work) {
  return { json: { ...cfg, _skip: true } };
}

const name = work.name.length > 30 ? work.name.substring(0, 27) + '...' : work.name;
let msg = '✏️ *' + (L.btn_edit || 'Редактирование') + '*\n\n';
