msg += '📏 ' + work.qty + ' ' + (work.unit || 'm²') + '\n\n';
msg += (L.edit_hint || 'Изменить количество:');

// Quantity edit buttons
const keyboard = [
  [
    { text: '-10', callback_data: 'qty_work_' + idx + '_minus10' },
    { text: '-1', callback_data: 'qty_work_' + idx + '_minus1' },
    { text: '+1', callback_data: 'qty_work_' + idx + '_plus1' },
    { text: '+10', callback_data: 'qty_work_' + idx + '_plus10' }
  ],
  [
    { text: '÷2', callback_data: 'qty_work_' + idx + '_half' },
    { text: '×2', callback_data: 'qty_work_' + idx + '_double' }
  ],
  [
    { text: '🗑 ' + (L.btn_delete || 'Удалить'), callback_data: 'delete_work_' + idx }
  ],
  [
    { text: '◀️ ' + (L.btn_done || 'Назад'), callback_data: 'done_editing' }
  ]
];

return { json: { ...cfg, msg, keyboard, chatId: cid } };

